import React, { useEffect, useMemo, useState } from "react";
import {
  Drawer,
  List,
  ListItemButton,
  ListItemText,
  Collapse,
  Box,
  Avatar,
  Typography,
} from "@mui/material";
import {
  ExpandLess,
  ExpandMore,
  Dashboard,
  Assessment,
  Groups,
  Payment,
  Inventory,
  HelpOutline,
  Settings,
  Category as CategoryIcon,
  Close as CloseIcon,
} from "@mui/icons-material";
import { Link, useLocation } from "react-router-dom";
import { BiGrid } from "react-icons/bi";
import { baseUrlImage, mobileNumberFilter } from "../../../baseUrl";
import { imageLogo } from "../../../asesets";
import aadhaardeposit from "../../../asesets/bill-payments/aadhaardeposit.png";
import aadhaarwithdraw from "../../../asesets/bill-payments/aadhaarwithdraw.png";

/* ------------------------------------------------------------------ *
 * Same visual language as AdminHeader: theme-aware tints derived from
 * --bs-primary2/3 via color-mix(), plus one fixed brass accent
 * reserved for "you are here" state, so it reads consistently across
 * the whole shell regardless of which theme is active.
 * ------------------------------------------------------------------ */
const mix = (pct, base = "var(--bs-primary2)", onto = "transparent") =>
  `color-mix(in srgb, ${base} ${pct}%, ${onto})`;

const V = {
  border: mix(16),
  hoverTint: mix(7),
  sectionTint: mix(5),
  iconChip: mix(6),
  radiusSm: "8px",
  radiusMd: "10px",
};

const ACCENT = "#C9971A";
const ACCENT_DEEP = "#A87B12";
const ACCENT_SOFT = mix(14, ACCENT, "var(--bs-primary3)");

const menuIcons = {
  Dashboard: <Dashboard fontSize="small" />,
  "All services": <CategoryIcon fontSize="small" />,
  Reports: <Assessment fontSize="small" />,
  Networks: <Groups fontSize="small" />,
  Payments: <Payment fontSize="small" />,
  Package: <Inventory fontSize="small" />,
  Value: <Payment fontSize="small" />,
  "Help & Support": <HelpOutline fontSize="small" />,
  Settings: <Settings fontSize="small" />,
};

const CHILD_SERVICE_ICONS = {
  "Aadhaar Deposit": aadhaardeposit,
  "Aadhaar Withdraw": aadhaarwithdraw,
};

