/* ------------------------------------------------------------------ *
 * Design tokens — professional light theme
 * ------------------------------------------------------------------ */
const T = {
  surface: "#FFFFFF",
  surfaceMuted: "#F6F8FB",
  border: "#E4E8EF",
  borderStrong: "#D6DCE5",
  textPrimary: "#111827",
  textSecondary: "#5B6472",
  brand: "#123B5C",       // deep slate-navy — signature accent
  brandSoft: "#E7EEF4",
  brandHover: "#0E2E48",
  gold: "#B8860B",         // muted goldenrod for wallet CTA (refined, not neon)
  goldSoft: "#FBF3E1",
  danger: "#DC2626",
  shadow: "0 10px 28px rgba(17, 24, 39, 0.08)",
  shadowSm: "0 4px 14px rgba(17, 24, 39, 0.06)",
};

const HeaderNavLink = ({ menu, location, closeMenus }) => {
  const [isHovered, setIsHovered] = useState(false);

  const isActiveParent =
    menu.children &&
    menu.children.some((child) => location.pathname.startsWith(child.route));
  const isSimpleActive = !menu.children && location.pathname === menu.route;

  const ParentLinkOrButton = menu.route && !menu.children ? Link : "span";

  const liProps = menu.children
    ? {
      onMouseEnter: () => setIsHovered(true),
      onMouseLeave: () => setIsHovered(false),
      className: `nav-item dropdown d-none d-lg-block ${isHovered ? "show" : ""
        }`,
    }
    : {
      className: "nav-item d-none d-lg-block",
    };

  const active = isActiveParent || isSimpleActive;

  return (
    <li {...liProps} key={menu.item}>
      <ParentLinkOrButton
        to={menu.route || "#"}
        onClick={menu.children ? (e) => e.preventDefault() : closeMenus}
        className={`nav-link ${active ? "active-link" : ""}`}
        style={{
          color: active ? T.brand : T.textPrimary,
          fontWeight: active ? 700 : 600,
          fontSize: "14px",
          cursor: menu.children ? "default" : "pointer",
          padding: "10px 14px",
          borderRadius: "8px",
          whiteSpace: "nowrap",
          transition: "background-color 0.15s ease, color 0.15s ease",
          backgroundColor: active ? T.brandSoft : "transparent",
        }}
      >
        {menu.item}
      </ParentLinkOrButton>

      {menu.children && (
        <ul
          className={`dropdown-menu ${isHovered ? "show" : ""} dropdown-scroll`}
          style={{
            position: "absolute",
            zIndex: 1000,
            backgroundColor: T.surface,
            padding: "8px",
            minWidth: "210px",
            top: "calc(100% + 6px)",
            left: 0,
            border: `1px solid ${T.border}`,
            borderRadius: "10px",
            boxShadow: T.shadow,
            listStyle: "none",
          }}
        >
          {menu.children.slice().sort((a, b) => a.item.localeCompare(b.item)).map((child) => {
            const childActive = location.pathname.startsWith(child.route);
            return (
              <li key={child.item}>
                <Link
                  to={child.route}
                  className={`dropdown-item ${childActive ? "active-link" : ""}`}
                  onClick={() => setIsHovered(false)}
                  style={{
                    color: childActive ? T.brand : T.textPrimary,
                    fontWeight: childActive ? 600 : 500,
                    backgroundColor: childActive ? T.brandSoft : "transparent",
                    display: "flex",
                    alignItems: "center",
                    padding: "8px 10px",
                    borderRadius: "6px",
                    fontSize: "13.5px",
                  }}
                >
                  <MdArrowRight style={{ marginRight: 5, color: T.textSecondary }} />
                  {child.item}
                </Link>
              </li>
            );
          })}
        </ul>
      )}
    </li>
  );
};

const WalletDropdownContent = ({
  walletData,
  storedUserType,
  userNumber,
  handleWalletClose,
}) => {
  const renderWalletCard = (walletName, balance, initial, allowed = true) => {
    if (!allowed) return null;

    return (
      <div
        key={walletName}
        className="d-flex align-items-center justify-content-between py-2"
        style={{ borderBottom: `1px solid ${T.border}`, minHeight: "44px" }}
      >
        <div className="d-flex align-items-center gap-2">
          <div
            className="rounded-circle d-flex justify-content-center align-items-center"
            style={{
              width: "30px",
              height: "30px",
              backgroundColor: T.brandSoft,
              border: `1px solid ${T.borderStrong}`,
            }}
          >
            <span
              className="fw-bold"
              style={{ fontSize: "12px", color: T.brand }}
            >
              {initial}
            </span>
          </div>
          <div>
            <div
              className="fw-semibold"
              style={{ fontSize: "13px", color: T.textPrimary }}
            >
              {walletName}
            </div>
            <div
              className="small"
              style={{ color: T.textSecondary, fontSize: "12.5px", fontWeight: 600 }}
            >
              &#x20B9; {balance}
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div
      className="wallet-dropdown-menu"
      style={{
        position: "absolute",
        top: "calc(100% + 8px)",
        right: "10px",
        zIndex: 1050,
        backgroundColor: T.surface,
        padding: "14px",
        minWidth: "240px",
        borderRadius: "12px",
        boxShadow: T.shadow,
        border: `1px solid ${T.border}`,
      }}
    >
      <h5
        style={{
          fontWeight: 700,
          fontSize: "13.5px",
          letterSpacing: "0.02em",
          textTransform: "uppercase",
          margin: "0 0 10px 0",
          color: T.textSecondary,
        }}
      >
        Wallet Balances
      </h5>

      <div style={{ padding: "0 2px" }}>
        <UserGuard currentUser={storedUserType} excludeUserList={[""]}>
          {renderWalletCard("Main Wallet", walletData?.main_wallet, "M", true)}
        </UserGuard>
        {storedUserType === "Retailer" &&
          !mobileNumberFilter?.includes(userNumber) &&
          renderWalletCard("AEPS Wallet", walletData?.aeps_wallet, "A", true)}
        <UserGuard currentUser={storedUserType} allowUserList={["Retailer"]}>
          {renderWalletCard(
            "Cashback Wallet",
            walletData?.cashback_wallet,
            "C",
            true
          )}
        </UserGuard>
        <UserGuard
          currentUser={storedUserType}
          allowUserList={["Api User", "reseller partner api user"]}
        >
          {renderWalletCard(
            "PayIn Wallet",
            walletData?.payin_wallet,
            "P",
            true
          )}
        </UserGuard>

        <UserGuard
          currentUser={storedUserType}
          excludeUserList={["Reseller", "reseller partner api user"]}
        >
          <Link
            to="/add-payment-request"
            onClick={handleWalletClose}
            className="btn d-flex align-items-center gap-2 px-3 py-2 rounded-pill mt-3"
            style={{
              fontSize: "13px",
              justifyContent: "center",
              backgroundColor: T.brand,
              border: "none",
              color: "#FFFFFF",
              fontWeight: 600,
              boxShadow: "0 4px 10px rgba(18, 59, 92, 0.25)",
            }}
          >
            <GiWallet size={16} />
            <span>Add Money</span>
          </Link>
        </UserGuard>
      </div>
    </div>
  );
};

function AdminHeader({
  walletData,
  profileOn,
  profileOf,
  toggle,
  tokenNoti,
  setProfileData,
  handleSidebar,
}) {
  const navigate = useNavigate();
  const location = useLocation();

  const walletRef = useRef(null);
  const profileRef = useRef(null);

  const [services, setServices] = useState([]);

  const [openThemeModal, setOpenThemeModal] = useState(false);

  useEffect(() => {
    const fetchServices = async () => {
      try {
        const response = await bpbsAllServiceList();
        if (!response.error) {
          setServices(response.data || []);
        } else {
          setServices([]);
        }
      } catch (error) {
        console.error("Error fetching services:", error);
        setServices([]);
      }
    };
    fetchServices();
  }, []);

  const { filteredMenuItems } = useMenuData(services);

  const userNumber = localStorage.getItem("regisNumber");
  const [data, setData] = useState(null);
  const [adminCount, setAdminCount] = useState(0);
  const [NotificationData, setNotificationData] = useState(null);
  const storedUserType = localStorage.getItem("userType");

  const [show, setShow] = useState(false);
  const [walletShow, setWalletShow] = useState(false);

  const handleClose = () => setShow(false);
  const handleWalletClose = () => setWalletShow(false);
  const closeMenus = () => { };

  const getDataProfile = async () => {
    try {
      const res = await Getprofile();
      setData(res?.data?.data);
      setProfileData(res?.data?.data);
      const userType = res?.data?.data?.user_type_id?.user_type || "";
      const userTypeId = res?.data?.data?.user_type_id?._id || "";
      setUserType(userType);
      setUserTypeId(userTypeId);
    } catch (error) { }
  };

  const notification = async () => {
    try {
      const res = await notifications();
      setAdminCount(res?.data?.data?.count || 0);
    } catch (error) { }
  };

  const notificationList = async (cc) => {
    try {
      const res = await notificationsList(cc, 0, cc == 0 ? true : false);
      setNotificationData(res?.data?.data);
    } catch (error) { }
  };

  useEffect(() => {
    getDataProfile();
    notification();
  }, []);

  const logOut = () => {
    window.localStorage.removeItem("userToken");
    window.localStorage.removeItem("userIdToken");
    window.localStorage.removeItem("openMenu");
    window.localStorage.removeItem("regisNumber");
    window.localStorage.removeItem("userType");
    window.localStorage.removeItem("userTypeId");
    localStorage.clear();
    navigate("/login-area");
  };

  const handleShow = () => {
    setShow(true);
    notificationList(adminCount);
    setTimeout(() => {
      notification();
    }, 500);
  };

  const handleWalletClick = () => {
    setWalletShow((prev) => !prev);
  };

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (walletRef.current && !walletRef.current.contains(event.target)) {
        setWalletShow(false);
      }

      if (
        profileRef.current &&
        !profileRef.current.contains(event.target) &&
        toggle
      ) {
        profileOf();
      }
    };

    document.addEventListener("mousedown", handleClickOutside);
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, [toggle]);

  const getAvatarUrl = () =>
    `https://ui-avatars.com/api/?name=${encodeURIComponent(
      data?.pan_name || data?.name || "User"
    )}&background=123B5C&color=fff&size=50`;

  return (
    <>
      <header
        className="HeaderMain"
        id="mainHeader"
        style={{
          backgroundColor: T.surface,
          borderBottom: `1px solid ${T.border}`,
          boxShadow: T.shadowSm,
        }}
      >
        <IconButton
          size="large"
          edge="start"
          color="inherit"
          aria-label="open drawer"
          sx={{ ml: 2, color: T.brand }}
          onClick={handleSidebar}
          id="sidebarToggleBtn"
          className="sidebar-toggle-btn d-inline-flex d-lg-none"
        >
          <MenuIcon />
        </IconButton>

        <img
          src={logoImage}
          alt="App Logo"
          className="logo-img"
          id="headerLogo"
          style={{ cursor: "pointer" }}
          onClick={() => navigate("/Dashboard")}
        />

        <div
          className="HeaderContainer d-flex justify-content-between align-items-center"
          id="topHeader"
        >
          <nav className="HeaderNav d-none d-lg-block" id="headerNav">
            <ul
              className="navbar-nav d-flex flex-row"
              id="headerNavList"
              style={{ listStyle: "none", padding: 0, margin: 0, gap: "2px" }}
            >
              {filteredMenuItems?.map((menu) => (
                <HeaderNavLink
                  key={menu.item}
                  menu={menu}
                  location={location}
                  closeMenus={closeMenus}
                />
              ))}
            </ul>
          </nav>

          <div
            className="HeaderRight text-white ms-auto d-flex align-items-center"
            id="headerRight"
            style={{ columnGap: "12px", marginLeft: "auto" }}
          >
            <div
              className="UserDetails dropdown d-lg-none"
              id="mobileUserDetails"
            >
              <div className="UserDetails dropdown d-lg-none">
                <div
                  className="UserDropdown dropdown-menu"
                  aria-labelledby="UserDropdown"
                  style={{
                    backgroundColor: T.surface,
                    border: `1px solid ${T.border}`,
                    borderRadius: "10px",
                    boxShadow: T.shadow,
                  }}
                >
                  <ul>
                    <li className="user-mob-balance">
                      <a href="javascript:void(0);" style={{ color: T.textPrimary }}>
                        <i>
                          <svg x={0} y={0} viewBox="0 0 28 28" fill={T.brand}>
                            <path d="M27.982,13.044 L26.627,13.044 L26.627,6.867 C26.627,5.386 25.411,4.182 23.916,4.182 L22.081,4.182 L20.202,0.836 C19.916,0.324 19.371,0.007 18.780,0.007 C18.505,0.007 18.232,0.077 17.990,0.210 L10.781,4.182 L2.728,4.182 C1.233,4.182 0.017,5.386 0.017,6.867 L0.017,25.307 C0.017,26.788 1.233,27.993 2.728,27.993 L23.916,27.993 C25.411,27.993 26.627,26.788 26.627,25.307 L26.627,19.892 L27.982,19.892 L27.982,13.044 L27.982,13.044 ZM23.916,5.256 C24.751,5.256 25.433,5.884 25.525,6.688 L23.488,6.688 L22.684,5.256 L23.916,5.256 ZM18.518,1.149 C18.772,1.007 19.114,1.106 19.254,1.357 L22.247,6.688 L8.463,6.688 L18.518,1.149 ZM25.543,25.307 C25.543,26.196 24.813,26.919 23.916,26.919 L2.728,26.919 C1.831,26.919 1.101,26.196 1.101,25.307 L1.101,6.867 C1.101,5.979 1.831,5.256 2.728,5.256 L8.831,5.256 L6.231,6.688 L3.067,6.688 C2.767,6.688 2.525,6.929 2.525,7.225 C2.525,7.522 2.767,7.763 3.067,7.763 L4.281,7.763 L24.091,7.763 L25.543,7.763 L25.543,13.044 L21.578,13.044 C19.737,13.044 18.239,14.529 18.239,16.353 L18.239,16.584 C18.239,18.408 19.737,19.892 21.578,19.892 L25.543,19.892 L25.543,25.307 L25.543,25.307 ZM26.898,18.818 L26.627,18.818 L21.578,18.818 C20.335,18.818 19.323,17.816 19.323,16.583 L19.323,16.352 C19.323,15.120 20.334,14.118 21.578,14.118 L26.627,14.118 L26.898,14.118 L26.898,18.818 ZM23.239,16.512 C23.239,17.167 22.703,17.698 22.042,17.698 C21.380,17.698 20.845,17.167 20.845,16.512 C20.845,15.857 21.380,15.326 22.042,15.326 C22.703,15.326 23.239,15.857 23.239,16.512 Z" />
                          </svg>
                        </i>
                        <span id="baldiv2" style={{ fontWeight: 700, color: T.brand }}>2162.81</span>
                      </a>
                    </li>
                    <li>
                      <a href="#" style={{ color: T.textPrimary }}>
                        <i>{/* Profile SVG */}</i>
                        <span>Profile</span>
                      </a>
                    </li>
                    <li>
                      <a href="#" style={{ color: T.textPrimary }}>
                        <i>{/* Complain SVG */}</i>
                        <span>Complain</span>
                      </a>
                    </li>
                    <li>
                      <a href="#" style={{ color: T.danger }}>
                        <i>{/* Logout SVG */}</i>
                        <span>Logout</span>
                      </a>
                    </li>
                  </ul>
                </div>
              </div>
            </div>
            <div className="d-none ">
              <ThemeSelector />
            </div>
            <div
              ref={walletRef}
              className="d-flex justify-content-center position-relative"
              onClick={handleWalletClick}
            >
              <button
                className="btn_custom d-flex align-items-center gap-2 px-4 py-2 rounded-pill"
                style={{
                  backgroundColor: T.surfaceMuted,
                  border: `1px solid ${T.border}`,
                }}
              >
                <GiWallet size={18} color={T.brand} />
                <span
                  className="d-none d-lg-inline"
                  style={{ color: T.textPrimary, fontWeight: 600, fontSize: "13.5px" }}
                >
                  Wallet
                </span>
              </button>

              {walletShow && (
                <WalletDropdownContent
                  walletData={walletData}
                  storedUserType={storedUserType}
                  userNumber={userNumber}
                  handleWalletClose={handleWalletClose}
                />
              )}
            </div>

            {storedUserType === "Super Distributor" ||
              storedUserType === "Distributor" ||
              storedUserType === "asm" ||
              storedUserType === "zsm"}

            <div className="dropdown header-profile2" ref={profileRef}>
              <div className="nav-link" onClick={profileOn}>
                <div className="header-media">
                  <img
                    src={data?.profile || getAvatarUrl()}
                    alt="profile"
                    style={{
                      width: 44,
                      height: 44,
                      borderRadius: "50%",
                      objectFit: "cover",
                      border: `2px solid ${T.border}`,
                    }}
                    onLoad={(e) => {
                      console.log("Image loaded:", e.target.src);
                    }}
                    onError={(e) => {
                      console.log("Error loading image:", e.target.src);
                      e.target.onerror = null; // prevent infinite loop
                      e.target.src = getAvatarUrl();
                    }}
                  />
                </div>
              </div>
              {toggle ? (
                <div className="dropdown-menu-end dropdown-menu-2">
                  <Box
                    sx={{
                      width: 300,
                      bgcolor: T.surface,
                      borderRadius: "12px",
                      overflow: "hidden",
                      border: `1px solid ${T.border}`,
                      boxShadow: T.shadow,
                    }}
                  >
                    {/* ===== Header ===== */}
                    <Box
                      sx={{
                        display: "flex",
                        alignItems: "center",
                        gap: 1.5,
                        px: 2,
                        py: 1.75,
                        bgcolor: T.surfaceMuted,
                      }}
                    >
                      <Avatar
                        src={
                          data?.profile
                            ? data?.profile
                            : `${baseUrlImage}${data.profile}`
                        }
                        sx={{
                          width: 46,
                          height: 46,
                          bgcolor: T.brandSoft,
                          color: T.brand,
                          fontWeight: 700,
                          border: `1px solid ${T.borderStrong}`,
                        }}
                      >
                        {data?.name?.[0]?.toUpperCase() || "U"}
                      </Avatar>

                      <Box sx={{ minWidth: 0 }}>
                        <Typography
                          variant="caption"
                          sx={{ color: T.textSecondary, fontWeight: 600, letterSpacing: "0.02em" }}
                        >
                          {data?.refer_id}
                        </Typography>

                        <Typography
                          variant="subtitle2"
                          title={data?.name}
                          noWrap
                          sx={{
                            color: T.textPrimary,
                            fontWeight: 700,
                            fontSize: "15px",
                            lineHeight: 1.3,
                            letterSpacing: "0.1px",
                          }}
                        >
                          {data?.name}
                        </Typography>
                        <Typography
                          variant="caption"
                          sx={{
                            color: T.brand,
                            fontWeight: 600,
                            fontSize: "11.5px",
                            textTransform: "uppercase",
                            letterSpacing: "0.04em",
                          }}
                        >
                          {storedUserType}
                        </Typography>
                      </Box>
                    </Box>

                    <Divider sx={{ borderColor: T.border }} />

                    {/* ===== Menu ===== */}
                    <List dense disablePadding sx={{ py: 0.5 }}>
                      <ListItemButton
                        component={Link}
                        to="profile"
                        onClick={profileOf}
                        sx={{
                          px: 2,
                          py: 1,
                          "&:hover": { bgcolor: T.brandSoft },
                        }}
                      >
                        <ListItemIcon sx={{ minWidth: 36, color: T.brand }}>
                          <PersonOutlineIcon fontSize="small" />
                        </ListItemIcon>
                        <ListItemText
                          primary="Profile"
                          primaryTypographyProps={{
                            fontSize: 14,
                            fontWeight: 500,
                            color: T.textPrimary,
                          }}
                        />
                      </ListItemButton>

                      <ListItemButton
                        onClick={() => {
                          setOpenThemeModal(true);
                          profileOf();
                        }}
                        sx={{
                          px: 2,
                          py: 1,
                          "&:hover": { bgcolor: T.brandSoft },
                        }}
                      >
                        <ListItemIcon sx={{ minWidth: 36, color: T.brand }}>
                          <PaletteOutlinedIcon fontSize="small" />
                        </ListItemIcon>
                        <ListItemText
                          primary="Theme Settings"
                          primaryTypographyProps={{
                            fontSize: 14,
                            fontWeight: 500,
                            color: T.textPrimary,
                          }}
                        />
                      </ListItemButton>

                      <ListItemButton
                        component={Link}
                        to="change_password"
                        onClick={profileOf}
                        sx={{
                          px: 2,
                          py: 1,
                          "&:hover": { bgcolor: T.brandSoft },
                        }}
                      >
                        <ListItemIcon sx={{ minWidth: 36, color: T.brand }}>
                          <LockOutlinedIcon fontSize="small" />
                        </ListItemIcon>
                        <ListItemText
                          primary="Password Change"
                          primaryTypographyProps={{
                            fontSize: 14,
                            fontWeight: 500,
                            color: T.textPrimary,
                          }}
                        />
                      </ListItemButton>

                      <ListItemButton
                        component={Link}
                        to="change_txnpassword"
                        onClick={profileOf}
                        sx={{
                          px: 2,
                          py: 1,
                          "&:hover": { bgcolor: T.brandSoft },
                        }}
                      >
                        <ListItemIcon sx={{ minWidth: 36, color: T.brand }}>
                          <PinOutlinedIcon fontSize="small" />
                        </ListItemIcon>
                        <ListItemText
                          primary="Pin Change"
                          primaryTypographyProps={{
                            fontSize: 14,
                            fontWeight: 500,
                            color: T.textPrimary,
                          }}
                        />
                      </ListItemButton>
                      {/* ===== Notifications (MOBILE ONLY) ===== */}
                      <ListItemButton
                        onClick={() => {
                          handleShow();
                          profileOf(); // close profile dropdown
                        }}
                        className="d-lg-none"
                        sx={{
                          px: 2,
                          py: 1,
                          "&:hover": { bgcolor: T.brandSoft },
                        }}
                      >
                        <ListItemIcon sx={{ minWidth: 36, color: T.brand }}>
                          <PiBellSimpleBold />
                        </ListItemIcon>
                        <ListItemText
                          primary="Notifications"
                          primaryTypographyProps={{
                            fontSize: 14,
                            fontWeight: 500,
                            color: T.textPrimary,
                          }}
                        />
                        {adminCount > 0 && (
                          <Box
                            sx={{
                              ml: "auto",
                              bgcolor: T.danger,
                              color: "#fff",
                              fontSize: "11px",
                              fontWeight: 700,
                              px: 1,
                              borderRadius: "10px",
                            }}
                          >
                            {adminCount}
                          </Box>
                        )}
                      </ListItemButton>
                    </List>

                    <Divider sx={{ borderColor: T.border }} />

                    {/* ===== Logout ===== */}
                    <ListItemButton
                      onClick={logOut}
                      sx={{
                        px: 2,
                        py: 1.25,
                        "&:hover": { bgcolor: "#FDECEC" },
                      }}
                    >
                      <ListItemIcon sx={{ minWidth: 36, color: T.danger }}>
                        <LogoutOutlinedIcon fontSize="small" />
                      </ListItemIcon>
                      <ListItemText
                        primary="Logout"
                        primaryTypographyProps={{
                          fontSize: 14,
                          fontWeight: 700,
                          color: T.danger,
                        }}
                      />
                    </ListItemButton>
                  </Box>
                </div>
              ) : (
                <></>
              )}
            </div>

            {/* Notification – DESKTOP ONLY */}
            <div className="d-none d-lg-block">
              <div className="RightActions">
                <div className="NotificationsMain dropdown">
                  <div
                    className="px-2 d-flex align-items-center justify-content-center"
                    onClick={handleShow}
                    style={{
                      cursor: "pointer",
                      width: "38px",
                      height: "38px",
                      borderRadius: "50%",
                      backgroundColor: T.surfaceMuted,
                      border: `1px solid ${T.border}`,
                      position: "relative",
                    }}
                  >
                    <span className="notification" style={{ position: "relative" }}>
                      <PiBellSimpleBold color={T.brand} size={18} />
                      {adminCount > 0 && (
                        <span
                          className="pulse"
                          style={{
                            position: "absolute",
                            top: "-6px",
                            right: "-10px",
                          }}
                        >
                          <div
                            className="circle pulse"
                            style={{
                              backgroundColor: T.danger,
                              color: "#fff",
                              fontSize: "10px",
                              fontWeight: 700,
                              minWidth: "16px",
                              height: "16px",
                              borderRadius: "9px",
                              display: "flex",
                              alignItems: "center",
                              justifyContent: "center",
                              padding: "0 4px",
                            }}
                          >
                            {adminCount}
                          </div>
                        </span>
                      )}
                    </span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        <input
          type="hidden"
          id="das_hidgetrechargevalues_url"
          defaultValue="https://m.masterpay.pro/Retailer/getRechargeValues"
          autoComplete="off"
        />
      </header>

      {["end"].map((placement, idx) => (
        <NotificationSide
          key={idx}
          placement={placement}
          tokenNoti={tokenNoti}
          name={placement}
          handleClose={handleClose}
          show={show}
          NotificationData={NotificationData}
        />
      ))}

      {openThemeModal && (
        <div
          style={{
            position: "fixed",
            top: 0,
            left: 0,
            width: "100vw",
            height: "100vh",
            background: "rgba(17, 24, 39, 0.35)",
            zIndex: 9999,
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            backdropFilter: "blur(3px)",
          }}
          onClick={() => setOpenThemeModal(false)}
        >
          <div
            style={{
              background: T.surface,
              padding: "24px",
              width: "500px",
              borderRadius: "16px",
              color: T.textPrimary,
              maxHeight: "80vh",
              overflowY: "auto",
              border: `1px solid ${T.border}`,
              boxShadow: T.shadow,
            }}
            onClick={(e) => e.stopPropagation()}
          >
            <h5 className="fw-bold mb-3 text-center" style={{ color: T.textPrimary }}>
              Theme Settings
            </h5>

            <ThemeSelector showOnlyGrid />

            <button
              className="btn w-100 mt-3"
              style={{
                backgroundColor: T.surfaceMuted,
                border: `1px solid ${T.border}`,
                color: T.textPrimary,
                fontWeight: 600,
                borderRadius: "8px",
                padding: "8px 0",
              }}
              onClick={() => setOpenThemeModal(false)}
            >
              Close
            </button>
          </div>
        </div>
      )}
    </>
  );
}
export default AdminHeader;